-- =========================================================
-- Silver Guard · 古典经典阅读模块
-- 数据库迁移脚本 v5.0
-- 新增：经典书籍、章节、阅读进度、书签
-- =========================================================
USE silver_guard;

SET NAMES utf8mb4;

-- =========================================================
-- 21 经典书籍表（ClassicalBook）
-- =========================================================
CREATE TABLE IF NOT EXISTS classical_book (
    id              BIGINT UNSIGNED  NOT NULL  AUTO_INCREMENT  COMMENT '书籍ID',
    title           VARCHAR(100)     NOT NULL                     COMMENT '书名',
    author          VARCHAR(64)      DEFAULT NULL                 COMMENT '作者/编者',
    dynasty         VARCHAR(32)      DEFAULT NULL                 COMMENT '朝代',
    category        VARCHAR(32)      NOT NULL  DEFAULT 'CLASSIC'  COMMENT '分类：CLASSIC/POETRY/HISTORY/PHILOSOPHY/HEALTH',
    cover_desc      VARCHAR(500)     DEFAULT NULL                 COMMENT '封面描述',
    summary         TEXT             NOT NULL                     COMMENT '书籍简介',
    total_chapters  INT              NOT NULL  DEFAULT 0          COMMENT '总章节数',
    tags            JSON             DEFAULT NULL                 COMMENT '标签JSON',
    sort_order      INT              NOT NULL  DEFAULT 0          COMMENT '排序',
    gmt_create      DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3)  COMMENT '创建时间',
    gmt_modified    DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3)  COMMENT '更新时间',
    deleted         TINYINT         NOT NULL  DEFAULT 0           COMMENT '软删除标记',
    PRIMARY KEY (id),
    KEY idx_category (category),
    KEY idx_sort (sort_order)
) ENGINE=InnoDB  DEFAULT CHARSET=utf8mb4  COLLATE=utf8mb4_unicode_ci  COMMENT='经典书籍表';

-- =========================================================
-- 22 章节内容表（ClassicalChapter）
-- =========================================================
CREATE TABLE IF NOT EXISTS classical_chapter (
    id              BIGINT UNSIGNED  NOT NULL  AUTO_INCREMENT  COMMENT '章节ID',
    book_id         BIGINT UNSIGNED  NOT NULL                     COMMENT '书籍ID',
    chapter_order   INT              NOT NULL                     COMMENT '章节序号',
    title           VARCHAR(200)     NOT NULL                     COMMENT '章节标题',
    content         TEXT             NOT NULL                     COMMENT '原文内容',
    translation     TEXT             DEFAULT NULL                 COMMENT '白话译文',
    annotation      TEXT             DEFAULT NULL                 COMMENT '注释/赏析',
    audio_url       VARCHAR(500)     DEFAULT NULL                 COMMENT '朗读音频URL',
    gmt_create      DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3)  COMMENT '创建时间',
    gmt_modified    DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3)  COMMENT '更新时间',
    deleted         TINYINT         NOT NULL  DEFAULT 0           COMMENT '软删除标记',
    PRIMARY KEY (id),
    UNIQUE KEY uk_book_chapter (book_id, chapter_order),
    KEY idx_book (book_id)
) ENGINE=InnoDB  DEFAULT CHARSET=utf8mb4  COLLATE=utf8mb4_unicode_ci  COMMENT='章节内容表';

-- =========================================================
-- 23 阅读进度表（ReadingProgress）
-- =========================================================
CREATE TABLE IF NOT EXISTS reading_progress (
    id              BIGINT UNSIGNED  NOT NULL  AUTO_INCREMENT  COMMENT '进度ID',
    user_id         BIGINT UNSIGNED  NOT NULL                     COMMENT '用户ID',
    book_id         BIGINT UNSIGNED  NOT NULL                     COMMENT '书籍ID',
    chapter_id      BIGINT UNSIGNED  NOT NULL                     COMMENT '当前章节ID',
    scroll_position INT              NOT NULL  DEFAULT 0          COMMENT '滚动位置',
    is_finished     TINYINT         NOT NULL  DEFAULT 0           COMMENT '是否读完',
    gmt_create      DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3)  COMMENT '创建时间',
    gmt_modified    DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3)  COMMENT '更新时间',
    deleted         TINYINT         NOT NULL  DEFAULT 0           COMMENT '软删除标记',
    PRIMARY KEY (id),
    UNIQUE KEY uk_user_book (user_id, book_id),
    KEY idx_user (user_id),
    KEY idx_book (book_id)
) ENGINE=InnoDB  DEFAULT CHARSET=utf8mb4  COLLATE=utf8mb4_unicode_ci  COMMENT='阅读进度表';

-- =========================================================
-- 24 书签表（Bookmark）
-- =========================================================
CREATE TABLE IF NOT EXISTS bookmark (
    id              BIGINT UNSIGNED  NOT NULL  AUTO_INCREMENT  COMMENT '书签ID',
    user_id         BIGINT UNSIGNED  NOT NULL                     COMMENT '用户ID',
    book_id         BIGINT UNSIGNED  NOT NULL                     COMMENT '书籍ID',
    chapter_id      BIGINT UNSIGNED  NOT NULL                     COMMENT '章节ID',
    note            VARCHAR(500)     DEFAULT NULL                 COMMENT '书签备注',
    gmt_create      DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3)  COMMENT '创建时间',
    gmt_modified    DATETIME(3)     NOT NULL  DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3)  COMMENT '更新时间',
    deleted         TINYINT         NOT NULL  DEFAULT 0           COMMENT '软删除标记',
    PRIMARY KEY (id),
    KEY idx_user (user_id),
    KEY idx_book (book_id)
) ENGINE=InnoDB  DEFAULT CHARSET=utf8mb4  COLLATE=utf8mb4_unicode_ci  COMMENT='书签表';

-- =========================================================
-- 初始化种子数据：经典书籍
-- =========================================================
INSERT INTO classical_book (title, author, dynasty, category, cover_desc, summary, total_chapters, tags, sort_order) VALUES
('论语', '孔子及其弟子', '春秋', 'CLASSIC', '儒家经典，四书之首，孔门弟子辑录', '《论语》是儒家学派的经典著作之一，由孔子的弟子及其再传弟子编撰而成。它以语录体和对话文体为主，记录了孔子及其弟子的言行，集中体现了孔子的政治主张、伦理思想、道德观念及教育原则等。', 20, '["儒家", "四书", "修身", "齐家", "治国"]', 1),
('道德经', '老子', '春秋', 'PHILOSOPHY', '道家根本经典，五千言玄妙之门', '《道德经》又称《老子》，是道家哲学思想的重要来源。全书仅五千余字，却涵盖宇宙观、人生观、政治观等丰富内容，以"道法自然"为核心思想，主张无为而治、柔弱胜刚强。', 81, '["道家", "哲学", "无为", "自然", "养生"]', 2),
('诗经', '佚名（孔子编订）', '周代', 'POETRY', '中国最早的诗歌总集，风雅颂三百篇', '《诗经》是中国第一部诗歌总集，收录了西周初年至春秋中叶的诗歌305篇。分为风、雅、颂三部分，内容涵盖爱情、劳动、战争、祭祀等，语言优美，意境深远。', 15, '["诗歌", "风雅颂", "文学", "民谣"]', 3),
('唐诗三百首', '蘅塘退士 编', '清（编）', 'POETRY', '熟读唐诗三百首，不会作诗也会吟', '《唐诗三百首》是一部流传很广的唐诗选集，选诗范围广泛，收录了唐代77位诗人的311首诗作。涵盖了五言古诗、七言古诗、五言律诗、七言律诗、五言绝句、七言绝句等多种体裁。', 8, '["诗歌", "唐诗", "李白", "杜甫", "文学"]', 4),
('三字经', '王应麟', '宋', 'CLASSIC', '人之初性本善，蒙学经典之冠', '《三字经》是中国的传统启蒙教材，三字一句朗朗上口。内容涵盖了历史、天文、地理、道德以及一些民间传说，所谓"熟读三字经，可知千古事"。', 6, '["蒙学", "启蒙", "历史", "道德"]', 5),
('弟子规', '李毓秀', '清', 'CLASSIC', '圣人训首孝悌，修身齐家之根本', '《弟子规》原名《训蒙文》，以《论语》"学而篇"为核心思想，具体列述弟子在家、出外、待人、接物与学习上应该恪守的守则规范。全文共360句，1080字。', 7, '["蒙学", "修身", "礼仪", "孝道"]', 6),
('菜根谭', '洪应明', '明', 'PHILOSOPHY', '咬得菜根则百事可做，人生智慧箴言', '《菜根谭》是明代洪应明收集编著的一部论述修养、人生、处世、出世的语录集。以儒道佛三家思想为基础，融合了处世智慧与生活哲学，文字简练明隽，兼采雅俗。', 4, '["处世", "修养", "人生", "哲学", "智慧"]', 7),
('孙子兵法', '孙武', '春秋', 'PHILOSOPHY', '兵学圣典，知己知彼百战不殆', '《孙子兵法》是中国现存最早的兵书，也是世界上最早的军事著作，被誉为"兵学圣典"。全书共十三篇，内容博大精深，思想精邃富赡，逻辑缜密严谨。', 13, '["兵法", "谋略", "哲学", "竞争"]', 8),
('黄帝内经·素问', '佚名', '战国', 'HEALTH', '中医理论奠基之作，养生祛病之根本', '《黄帝内经》是中国最早的医学典籍，分《素问》和《灵枢》两部分。它建立了中医学的"阴阳五行"、"脉象"、"藏象"、"经络"等学说，是中医养生保健的理论基础。', 24, '["中医", "养生", "阴阳", "经络", "健康"]', 9),
('千字文', '周兴嗣', '梁', 'CLASSIC', '天地玄黄宇宙洪荒，一夜白头的千字绝唱', '《千字文》由一千个不重复的汉字组成的韵文，内容涵盖天文、地理、历史、伦理、教育等各方面。相传梁武帝命周兴嗣一夜编成，周兴嗣一夜白发。', 4, '["蒙学", "书法", "识字", "天文", "地理"]', 10);

-- =========================================================
-- 初始化种子数据：论语 章节（精选20篇）
-- =========================================================
INSERT INTO classical_chapter (book_id, chapter_order, title, content, translation, annotation) VALUES
(1, 1, '学而篇第一', '子曰："学而时习之，不亦说乎？有朋自远方来，不亦乐乎？人不知而不愠，不亦君子乎？"\n\n有子曰："其为人也孝弟，而好犯上者，鲜矣；不好犯上，而好作乱者，未之有也。君子务本，本立而道生。孝弟也者，其为仁之本与！"\n\n子曰："巧言令色，鲜矣仁！"\n\n曾子曰："吾日三省吾身：为人谋而不忠乎？与朋友交而不信乎？传不习乎？"', '孔子说："学习并且按时温习，不也很愉快吗？有朋友从远方来，不也很快乐吗？别人不了解自己却不生气，不也是君子吗？"\n\n有子说："为人孝顺父母、尊敬兄长，却喜欢冒犯上级的人，很少见；不喜欢冒犯上级，却喜欢造反作乱的人，从来没有过。君子专心致力于根本，根本建立了，道就会产生。孝顺父母、尊敬兄长，这就是仁的根本吧！"\n\n孔子说："花言巧语、装出和善面孔的人，很少是仁德的。"\n\n曾子说："我每天多次反省自己：为别人办事是否尽心竭力了？与朋友交往是否诚实守信了？老师传授的知识是否复习了？"', '本章为《论语》开篇，提出了学习的快乐、交友的喜悦和君子的修养。三句话层层递进，涵盖了求知、社交、修身的三个层面。'),
(1, 2, '为政篇第二', '子曰："为政以德，譬如北辰，居其所而众星共之。"\n\n子曰："《诗》三百，一言以蔽之，曰：''思无邪''。"\n\n子曰："吾十有五而志于学，三十而立，四十而不惑，五十而知天命，六十而耳顺，七十而从心所欲，不逾矩。"', '孔子说："以道德教化来治理政事，就像北极星一样，安居在自己的位置上，而群星都环绕着它。"\n\n孔子说："《诗经》三百篇，用一句话概括，就是\'思想纯正无邪念\'。"\n\n孔子说："我十五岁立志学习，三十岁能自立于世，四十岁不被外界迷惑，五十岁懂得了天命，六十岁能正确对待各种言论，七十岁能随心所欲而不越出规矩。"', '本篇集中阐述了孔子的政治思想，提出了"德治"的核心主张。同时记述了孔子自述的人生历程，成为后世中国人理想的人生坐标。'),
(1, 3, '八佾篇第三', '孔子谓季氏："八佾舞于庭，是可忍也，孰不可忍也？"\n\n子曰："人而不仁，如礼何？人而不仁，如乐何？"\n\n子曰："《关雎》乐而不淫，哀而不伤。"', '孔子谈到季氏，说："他用六十四人在庭院中舞蹈，这样的事都能容忍，还有什么事不能容忍？"\n\n孔子说："一个人没有仁德，如何对待礼呢？一个人没有仁德，如何对待乐呢？"\n\n孔子说："《关雎》这首诗，快乐而不放荡，忧愁而不哀伤。"', '本篇主要讨论礼乐制度。孔子认为礼乐的根本在于"仁"，外在的礼仪形式必须以内在的仁德为基础。'),
(1, 4, '里仁篇第四', '子曰："里仁为美。择不处仁，焉得知？"\n\n子曰："不仁者不可以久处约，不可以长处乐。仁者安仁，知者利仁。"\n\n子曰："富与贵，是人之所欲也；不以其道得之，不处也。贫与贱，是人之所恶也；不以其道得之，不去也。君子去仁，恶乎成名？君子无终食之间违仁，造次必于是，颠沛必于是。"', '孔子说："居住在有仁德的地方才是好的。选择住处而不选择有仁德的地方，怎么能算明智呢？"\n\n孔子说："没有仁德的人不能长久地处于贫困中，也不能长久地处于安乐中。仁德的人安于仁，聪明的人利用仁。"\n\n孔子说："财富和显贵，这是人人都想要的；但不用正当的方法得到它，君子不会接受。贫穷和卑贱，这是人人都厌恶的；但不用正当的方法摆脱它，君子不会去做。君子离开了仁德，怎么能成就名声呢？君子在吃一顿饭的时间之内也不会离开仁德，在仓促匆忙的时候必定如此，在颠沛流离的时候也必定如此。"', '本篇集中论述了"仁"这一核心概念。孔子强调仁是人的根本，无论富贵贫贱都不能违背。'),
(1, 5, '公冶长篇第五', '子谓公冶长："可妻也。虽在缧绁之中，非其罪也。"以其子妻之。\n\n子谓子贱："君子哉若人！鲁无君子者，斯焉取斯？"\n\n子曰："始吾于人也，听其言而信其行；今吾于人也，听其言而观其行。"', '孔子评论公冶长说："可以把女儿嫁给他。他虽然被关在监狱中，但不是他的罪过。"于是把女儿嫁给了他。\n\n孔子评论子贱说："这个人是君子啊！如果鲁国没有君子，他从哪里学到这种品德呢？"\n\n孔子说："起初我对于人，听了他的话就相信他的行为；现在我对于人，听了他的话还要观察他的行为。"', '本篇主要记载孔子对弟子及古人的评价，体现了孔子知人论事的智慧。"听其言而观其行"成为后世评价人的重要标准。'),
(1, 6, '雍也篇第六', '子曰："贤哉，回也！一箪食，一瓢饮，在陋巷，人不堪其忧，回也不改其乐。贤哉，回也！"\n\n子曰："质胜文则野，文胜质则史。文质彬彬，然后君子。"\n\n子曰："知之者不如好之者，好之者不如乐之者。"', '孔子说："颜回是多么贤德啊！一竹筐饭，一瓢水，住在简陋的小巷里，别人都忍受不了那种困苦，颜回却不改变他的快乐。颜回是多么贤德啊！"\n\n孔子说："质朴超过文采就显得粗野，文采超过质朴就显得虚浮。文采和质朴配合适当，这才是君子。"\n\n孔子说："懂得它的人不如喜爱它的人，喜爱它的人不如以它为乐的人。"', '本篇提出了"文质彬彬"的君子标准和"知之者不如好之者，好之者不如乐之者"的学习境界，对后世教育思想影响深远。'),
(1, 7, '述而篇第七', '子曰："述而不作，信而好古，窃比于我老彭。"\n\n子曰："默而识之，学而不厌，诲人不倦，何有于我哉？"\n\n子曰："德之不修，学之不讲，闻义不能徙，不善不能改，是吾忧也。"\n\n子曰："不义而富且贵，于我如浮云。"', '孔子说："只传述而不创作，相信并爱好古代文化，我私下把自己比作老彭。"\n\n孔子说："默默记住所学的知识，学习而不满足，教导别人而不疲倦，对我来说还有什么呢？"\n\n孔子说："品德不修养，学问不讲习，听到义不能去做，有缺点不能改正，这些都是我所忧虑的。"\n\n孔子说："用不正当手段得来的富贵，对我来说就像天上的浮云一样。"', '本篇是孔子自述其治学精神和为人准则的重要篇章。"学而不厌，诲人不倦"成为千古名言。'),
(1, 8, '泰伯篇第八', '子曰："泰伯，其可谓至德也已矣。三以天下让，民无得而称焉。"\n\n子曰："恭而无礼则劳，慎而无礼则葸，勇而无礼则乱，直而无礼则绞。"\n\n曾子曰："士不可以不弘毅，任重而道远。仁以为己任，不亦重乎？死而后已，不亦远乎？"', '孔子说："泰伯，可以称得上是品德最高的人了。多次把天下让给弟弟，老百姓简直找不到合适的词语来称赞他。"\n\n孔子说："恭敬而不懂礼就会劳累，谨慎而不懂礼就会畏缩，勇敢而不懂礼就会作乱，直率而不懂礼就会刻薄。"\n\n曾子说："读书人不可以不心胸宽广、意志坚强，因为责任重大而路途遥远。把实现仁作为自己的责任，不是很重大吗？到死才停止，不是很遥远吗？"', '本篇"任重道远"、"死而后已"等成语均出自此章，体现了儒家积极入世、担当责任的崇高精神。'),
(1, 9, '子罕篇第九', '子绝四：毋意，毋必，毋固，毋我。\n\n子在川上曰："逝者如斯夫！不舍昼夜。"\n\n子曰："三军可夺帅也，匹夫不可夺志也。"\n\n子曰："岁寒，然后知松柏之后凋也。"', '孔子杜绝了四种毛病：不凭空猜测，不绝对肯定，不固执己见，不唯我独尊。\n\n孔子在河边说："消逝的时光就像这河水一样啊！日夜不停地流去。"\n\n孔子说："三军的主帅可以被夺去，但一个普通人的志向却不能被夺去。"\n\n孔子说："天气寒冷了，才知道松柏是最后凋零的。"', '本篇提出了"毋意毋必毋固毋我"的治学态度和"匹夫不可夺志"的人格精神，以及"逝者如斯"的时光感悟。'),
(1, 10, '颜渊篇第十二', '颜渊问仁。子曰："克己复礼为仁。一日克己复礼，天下归仁焉。为仁由己，而由人乎哉？"颜渊曰："请问其目。"子曰："非礼勿视，非礼勿听，非礼勿言，非礼勿动。"\n\n仲弓问仁。子曰："出门如见大宾，使民如承大祭。己所不欲，勿施于人。在邦无怨，在家无怨。"', '颜渊问什么是仁。孔子说："约束自己使言行符合礼，就是仁。一旦能做到这样，天下的人都会称赞你是仁人。实践仁德全靠自己，难道还靠别人吗？"颜渊说："请问具体条目。"孔子说："不合礼的不看，不合礼的不听，不合礼的不说，不合礼的不做。"\n\n仲弓问什么是仁。孔子说："出门做事如同接待贵宾，役使百姓如同承当重大祭祀。自己不想做的事，不要强加给别人。在国家中没有怨恨，在家族中没有怨恨。"', '本章是《论语》中最重要的"问仁"章节。"克己复礼"和"己所不欲勿施于人"是儒家伦理思想的核心表述。'),
(1, 11, '子路篇第十三', '子曰："其身正，不令而行；其身不正，虽令不从。"\n\n子曰："无欲速，无见小利。欲速则不达，见小利则大事不成。"\n\n子曰："君子和而不同，小人同而不和。"\n\n子曰："君子泰而不骄，小人骄而不泰。"', '孔子说："自身端正，不发命令也能施行；自身不端正，即使发命令也不服从。"\n\n孔子说："不要图快，不要贪图小利。图快反而达不到目的，贪图小利就做不成大事。"\n\n孔子说："君子和谐相处但不盲目附和，小人盲目附和却不能和谐相处。"\n\n孔子说："君子安详舒泰而不骄傲，小人骄傲而不安详舒泰。"', '本篇集中论述了为政之道和君子小人之辨。"欲速则不达"、"和而不同"等成语皆出自此。'),
(1, 12, '宪问篇第十四', '子曰："邦有道，谷；邦无道，谷，耻也。"\n\n子曰："君子耻其言而过其行。"\n\n或曰："以德报怨，何如？"子曰："何以报德？以直报怨，以德报德。"\n\n子曰："不怨天，不尤人，下学而上达。知我者其天乎！"', '孔子说："国家政治清明，可以做官领俸禄；国家政治黑暗，还做官领俸禄，这就是耻辱。"\n\n孔子说："君子以说得多做得少为耻。"\n\n有人说："用恩德来回报怨恨，怎么样？"孔子说："那用什么来回报恩德呢？应该用公平正直来回报怨恨，用恩德来回报恩德。"\n\n孔子说："不怨恨天，不责备人，学习平常的知识而领悟高深的道理。了解我的大概只有天吧！"', '本篇"以直报怨"的论述与老子"报怨以德"形成鲜明对比，体现了儒道两家处世哲学的不同。'),
(1, 13, '卫灵公篇第十五', '子曰："人无远虑，必有近忧。"\n\n子曰："躬自厚而薄责于人，则远怨矣。"\n\n子曰："君子求诸己，小人求诸人。"\n\n子贡问曰："有一言而可以终身行之者乎？"子曰："其恕乎！己所不欲，勿施于人。"', '孔子说："一个人没有长远的考虑，一定会有眼前的忧患。"\n\n孔子说："多责备自己而少责备别人，就可以远离怨恨了。"\n\n孔子说："君子要求自己，小人要求别人。"\n\n子贡问道："有没有一个字可以终身奉行的呢？"孔子说："那就是恕吧！自己不想做的事，不要强加给别人。"', '本篇"人无远虑必有近忧"、"己所不欲勿施于人"等成为中国人处世智慧的核心格言。'),
(1, 14, '季氏篇第十六', '孔子曰："益者三友，损者三友。友直，友谅，友多闻，益矣。友便辟，友善柔，友便佞，损矣。"\n\n孔子曰："益者三乐，损者三乐。乐节礼乐，乐道人之善，乐多贤友，益矣。乐骄乐，乐佚游，乐宴乐，损矣。"\n\n孔子曰："君子有三戒：少之时，血气未定，戒之在色；及其壮也，血气方刚，戒之在斗；及其老也，血气既衰，戒之在得。"', '孔子说："有益的朋友有三种，有害的朋友有三种。与正直的人交朋友，与诚信的人交朋友，与见闻广博的人交朋友，是有益的。与谄媚逢迎的人交朋友，与表面奉承而背后诽谤的人交朋友，与花言巧语的人交朋友，是有害的。"\n\n孔子说："有益的快乐有三种，有害的快乐有三种。以礼乐节制为乐，以称道别人的优点为乐，以多交贤德的朋友为乐，是有益的。以骄奢放纵为乐，以游荡无度为乐，以宴饮作乐为乐，是有害的。"\n\n孔子说："君子有三件应该警戒的事：年轻时，血气未定，要警戒美色；到了壮年，血气方刚，要警戒争强好斗；到了老年，血气已经衰弱，要警戒贪得无厌。"', '本篇"三友"、"三乐"、"三戒"汇集了孔子的人生智慧，特别是"老年戒之在得"对老年人尤为深刻。'),
(1, 15, '阳货篇第十七', '子曰："性相近也，习相远也。"\n\n子曰："唯上知与下愚不移。"\n\n子张问仁于孔子。孔子曰："能行五者于天下为仁矣。"请问之。曰："恭、宽、信、敏、惠。恭则不侮，宽则得众，信则人任焉，敏则有功，惠则足以使人。"', '孔子说："人的本性是相近的，但由于习染不同而相差甚远。"\n\n孔子说："只有最上等的智者和最下等的愚人是不可改变的。"\n\n子张向孔子问仁。孔子说："能够在天下实行五种品德就是仁了。"子张请教是什么。孔子说："恭敬、宽厚、诚信、勤敏、慈惠。恭敬就不会受侮辱，宽厚就能得到众人拥护，诚信就能得到别人任用，勤敏就能取得成功，慈惠就能够使唤人。"', '本篇"性相近，习相远"揭示了后天教育的重要性，是中国教育思想的重要基石。'),
(1, 16, '微子篇第十八', '微子去之，箕子为之奴，比干谏而死。孔子曰："殷有三仁焉。"\n\n楚狂接舆歌而过孔子曰："凤兮凤兮！何德之衰？往者不可谏，来者犹可追。已而，已而！今之从政者殆而！"孔子下，欲与之言。趋而辟之，不得与之言。', '（纣王昏乱）微子离开了他，箕子被降为奴隶，比干因劝谏而被杀死。孔子说："殷朝有三位仁人啊。"\n\n楚国的狂人接舆唱着歌走过孔子的车旁："凤凰啊凤凰！你的德行为何如此衰微？过去的已不可挽回，未来的还来得及追赶。算了吧，算了吧！现在从政的人危险啊！"孔子下车，想和他说话。接舆快步避开，孔子没能和他说上话。', '本篇记载了孔子周游列国时遇到的隐士故事。"往者不可谏，来者犹可追"成为珍惜当下、面向未来的经典名言。'),
(1, 17, '子张篇第十九', '子张曰："士见危致命，见得思义，祭思敬，丧思哀，其可已矣。"\n\n子夏曰："博学而笃志，切问而近思，仁在其中矣。"\n\n子贡曰："君子之过也，如日月之食焉：过也，人皆见之；更也，人皆仰之。"', '子张说："读书人见到危险能献出生命，见到利益能想到道义，祭祀时想着恭敬，居丧时想着哀痛，那就可以了。"\n\n子夏说："广泛学习而坚定志向，恳切发问而思考当前的问题，仁就在其中了。"\n\n子贡说："君子的过错，就像日食月食一样：犯了错，人人都看得见；改正了，人人都仰望着。"', '本篇记载了孔子弟子们的言论。"博学笃志，切问近思"成为后世治学箴言。'),
(1, 18, '尧曰篇第二十', '尧曰："咨！尔舜！天之历数在尔躬，允执其中。四海困穷，天禄永终。"舜亦以命禹。\n\n曰："予小子履，敢用玄牡，敢昭告于皇皇后帝：有罪不敢赦。帝臣不蔽，简在帝心。朕躬有罪，无以万方；万方有罪，罪在朕躬。"', '尧说："唉！你舜啊！天命已经落到你身上了，要真诚地持守中正之道。如果天下百姓困苦贫穷，上天赐给你的禄位就会永远终止。"舜也用同样的话告诫禹。\n\n（商汤）说："我小子履，谨用黑色公牛作祭品，谨向伟大的天帝祷告：对有罪的人我不敢擅自赦免。您的臣仆的善恶我不敢隐瞒，您的心里是清楚的。我本人有罪，不要牵连天下百姓；天下百姓有罪，罪责都在我一人身上。"', '本篇为《论语》终篇，记述了尧舜禹汤的治国之道，强调了"允执其中"的中庸思想和"万方有罪，罪在朕躬"的担当精神。'),
(1, 19, '学而篇·精选句', '曾子曰："慎终追远，民德归厚矣。"\n\n子禽问于子贡曰："夫子至于是邦也，必闻其政，求之与？抑与之与？"子贡曰："夫子温、良、恭、俭、让以得之。夫子之求之也，其诸异乎人之求之与？"\n\n有子曰："礼之用，和为贵。先王之道，斯为美。小大由之，有所不行。知和而和，不以礼节之，亦不可行也。"', '曾子说："谨慎地对待父母的丧事，追念远代的祖先，百姓的道德就会归于淳厚。"\n\n子禽问子贡说："夫子每到一个国家，必定能听到这个国家的政事，是求来的呢？还是别人主动告诉他的？"子贡说："夫子是靠温和、善良、恭敬、节俭、谦让来获得的。夫子求取的方法，大概与别人求取的方法不同吧？"\n\n有子说："礼的应用，以和谐为贵。古代君王的治国之道，最可贵的地方就在这里。但不论大事小事都按和谐的办法去做，有时候也行不通。为和谐而和谐，不用礼来节制，也是不可行的。"', '本篇精选了《学而篇》中关于"温良恭俭让"和"礼之用和为贵"的经典论述，是儒家修身养性的重要准则。'),
(1, 20, '述而篇·精选句', '叶公问孔子于子路，子路不对。子曰："女奚不曰，其为人也，发愤忘食，乐以忘忧，不知老之将至云尔。"\n\n子曰："三人行，必有我师焉。择其善者而从之，其不善者而改之。"\n\n子以四教：文、行、忠、信。\n\n子曰："君子坦荡荡，小人长戚戚。"', '叶公向子路询问孔子是怎样的一个人，子路没有回答。孔子说："你为什么不这样说，他的为人，发愤用功时忘记了吃饭，快乐时忘记了忧愁，不知道衰老就要到来，如此而已。"\n\n孔子说："几个人一起走路，其中必定有可以做我老师的人。选择他们的优点去学习，看到他们的缺点就自我反省改正。"\n\n孔子以四种内容教育学生：文献典籍、社会实践、忠诚、守信。\n\n孔子说："君子心胸宽广坦荡，小人总是忧愁不安。"', '本篇精选了孔子自述的治学精神。"发愤忘食，乐以忘忧，不知老之将至"是老年人学习的最佳状态。"三人行必有我师"、"君子坦荡荡"等成语均出自此。');

-- =========================================================
-- 初始化种子数据：道德经 章节（精选12章）
-- =========================================================
INSERT INTO classical_chapter (book_id, chapter_order, title, content, translation, annotation) VALUES
(2, 1, '第一章 · 道可道', '道可道，非常道；名可名，非常名。\n无名天地之始，有名万物之母。\n故常无欲，以观其妙；常有欲，以观其徼。\n此两者同出而异名，同谓之玄。玄之又玄，众妙之门。', '可以用语言表达的道，就不是永恒不变的道；可以用名字称呼的名，就不是永恒不变的名。\n无，是天地创生的本源；有，是万物产生的根源。\n所以常常从无欲中去观照道的奥妙；常常从有欲中去观照道的端倪。\n无和有这两者同出一源而名称不同，都可以说是幽深的。幽深又幽深，是一切奥妙的门径。', '本章为《道德经》开篇，提出了"道"这一核心概念。"道"是宇宙万物的本源和规律，它超越语言和概念，只能通过直觉体悟。'),
(2, 2, '第二章 · 天下皆知', '天下皆知美之为美，斯恶已；皆知善之为善，斯不善已。\n故有无相生，难易相成，长短相较，高下相倾，音声相和，前后相随。\n是以圣人处无为之事，行不言之教。万物作焉而不辞，生而不有，为而不恃，功成而弗居。夫唯弗居，是以不去。', '天下人都知道美之所以为美，丑的观念就产生了；都知道善之所以为善，不善的观念就产生了。\n所以有和无互相生成，难和易互相成就，长和短互相比较，高和下互相倾倚，音和声互相和谐，前和后互相跟随。\n因此圣人以无为的态度来处理世事，实行不言的教导。万物兴起而不加干涉，生养万物而不据为己有，有所施为而不自恃有恩，功业成就而不自居其功。正因为不居功，所以功业不会失去。', '本章阐述了老子的辩证法思想，指出一切对立概念都是相互依存、相互转化的。圣人的"无为"并非消极不作为，而是顺应自然规律。'),
(2, 3, '第八章 · 上善若水', '上善若水。水善利万物而不争，处众人之所恶，故几于道。\n居善地，心善渊，与善仁，言善信，政善治，事善能，动善时。\n夫唯不争，故无尤。', '最高的善就像水一样。水善于滋润万物而不与万物相争，停留在众人都不喜欢的低洼之处，所以最接近于道。\n（最善的人）居处善于选择地方，心胸善于保持深沉，待人善于真诚仁爱，说话善于恪守信用，为政善于治理，做事善于发挥能力，行动善于把握时机。\n正因为有不争的美德，所以没有过失。', '本章以水为喻，说明了"不争"的处世哲学。水看似柔弱，却能穿石；看似处下，却滋养万物。这是老年人养生处世的绝佳智慧。'),
(2, 4, '第九章 · 功遂身退', '持而盈之，不如其已；揣而锐之，不可长保。\n金玉满堂，莫之能守；富贵而骄，自遗其咎。\n功遂身退，天之道也。', '自满自持，不如适时停止；锋芒毕露，难以长久保持。\n金玉满堂，没有人能守得住；富贵而骄横，就会给自己留下祸患。\n功业成就了就退隐，这是符合自然规律的。', '本章提出了"功成身退"的智慧。对于老年人来说，懂得适时放下、知足常乐，是一种大智慧。'),
(2, 5, '第十二章 · 五色令人目盲', '五色令人目盲，五音令人耳聋，五味令人口爽，驰骋畋猎令人心发狂，难得之货令人行妨。\n是以圣人为腹不为目，故去彼取此。', '缤纷的色彩使人眼花缭乱，嘈杂的声音使人听觉失灵，丰盛的食物使人口舌麻木，纵情狩猎使人心放荡发狂，稀有的物品使人行为不轨。\n因此圣人只求温饱而不追求声色之娱，所以摒弃物欲的诱惑而保持安定的生活。', '本章告诫人们过度追求感官享受会损害身心健康。对于老年人，简约生活、清心寡欲才是养生之道。'),
(2, 6, '第十六章 · 致虚守静', '致虚极，守静笃。万物并作，吾以观复。\n夫物芸芸，各复归其根。归根曰静，静曰复命。复命曰常，知常曰明。不知常，妄作凶。\n知常容，容乃公，公乃全，全乃天，天乃道，道乃久，没身不殆。', '达到极度的虚空，保持深沉的宁静。万物蓬勃生长，我从中观察它们的循环往复。\n万物纷纷芸芸，各自回归到它们的根本。回归根本叫做静，静叫做复归于生命。复归于生命叫做自然规律，认识了自然规律叫做明智。不认识自然规律，轻举妄动就会招来灾祸。\n认识自然规律就能包容，包容就能公正，公正就能周全，周全就能符合自然，符合自然就能符合道，符合道就能长久，终身不会遭到危险。', '本章是老子养生思想的核心。"致虚极，守静笃"教导人们通过静心内观来体悟生命本质，对老年人修身养性极为重要。'),
(2, 7, '第二十二章 · 曲则全', '曲则全，枉则直，洼则盈，敝则新，少则得，多则惑。\n是以圣人抱一为天下式。不自见，故明；不自是，故彰；不自伐，故有功；不自矜，故长。\n夫唯不争，故天下莫能与之争。古之所谓"曲则全"者，岂虚言哉！诚全而归之。', '委曲才能保全，弯曲才能伸直，低洼才能充盈，破旧才能更新，少取才能获得，贪多反而迷惑。\n因此圣人坚守"道"作为天下的准则。不自我表现，所以能明达；不自以为是，所以能彰显；不自我夸耀，所以能有功；不自高自大，所以能长久。\n正因为不与人争，所以天下没有人能和他争。古人所说的"委曲才能保全"这话，难道是空话吗？确实能使人保全而归于道。', '本章"曲则全"的智慧告诉我们，有时候退一步海阔天空。老年人以柔克刚、以退为进的处世哲学，正是此章精髓。'),
(2, 8, '第三十三章 · 自知者明', '知人者智，自知者明。\n胜人者有力，自胜者强。\n知足者富。\n强行者有志。\n不失其所者久。\n死而不亡者寿。', '了解别人的人是有智慧的，了解自己的人是真正明智的。\n战胜别人的人是有力量的，战胜自己的人是真正强大的。\n知道满足的人是富有的。\n坚持不懈的人是有志气的。\n不丧失自己根基的人才能长久。\n身死而精神不灭的人才是真正的长寿。', '本章是全书中最为精炼的人生格言。"自知者明"、"自胜者强"、"知足者富"、"死而不亡者寿"等句，每句都是老年人修身养性的金玉良言。'),
(2, 9, '第四十四章 · 知足不辱', '名与身孰亲？身与货孰多？得与亡孰病？\n甚爱必大费，多藏必厚亡。\n故知足不辱，知止不殆，可以长久。', '名声和生命相比哪一个更亲？生命和财富相比哪一个更贵重？获得和失去相比哪一个更有害？\n过分的爱惜必定会付出巨大的耗费，过多的收藏必定会招致惨重的损失。\n所以知道满足就不会受到屈辱，知道适可而止就不会遇到危险，这样才能长久平安。', '本章教导人们珍视生命胜过名利财富。"知足不辱，知止不殆"是老年人安享晚年的至理名言。'),
(2, 10, '第六十七章 · 我有三宝', '天下皆谓我道大，似不肖。夫唯大，故似不肖。若肖，久矣其细也夫！\n我有三宝，持而保之：一曰慈，二曰俭，三曰不敢为天下先。\n慈故能勇，俭故能广，不敢为天下先故能成器长。\n今舍慈且勇，舍俭且广，舍后且先，死矣！\n夫慈，以战则胜，以守则固。天将救之，以慈卫之。', '天下人都说我的道很大，好像不像任何具体的东西。正因为大，所以不像任何具体的东西。如果像，早就变得渺小了！\n我有三件法宝，一直保持着：第一是慈爱，第二是节俭，第三是不敢居于天下人的前面。\n有了慈爱，所以能勇敢；有了节俭，所以能广博；不敢居于天下人的前面，所以能成为万物的首领。\n现在如果舍弃慈爱而追求勇敢，舍弃节俭而追求广博，舍弃退让而追求争先，那就死路一条了！\n慈爱，用来征战就能胜利，用来守卫就能坚固。上天要救助谁，就会用慈爱来保护他。', '本章"三宝"——慈、俭、不敢为天下先，是老子处世哲学的精髓。慈爱待人、勤俭节约、谦逊退让，是老年人颐养天年的三大法宝。'),
(2, 11, '第七十一章 · 知不知上', '知不知，尚矣；不知知，病也。\n圣人不病，以其病病。夫唯病病，是以不病。', '知道自己有所不知，这是最好的；不知道却自以为知道，这就是毛病。\n圣人没有这种毛病，因为他把这种毛病当作毛病。正因为把毛病当作毛病，所以没有毛病。', '本章教导人们要有"自知之明"，承认自己知识的局限。老年人保持谦逊好学的态度，是精神不老的表现。'),
(2, 12, '第八十一章 · 信言不美', '信言不美，美言不信。\n善者不辩，辩者不善。\n知者不博，博者不知。\n圣人不积，既以为人己愈有，既以与人己愈多。\n天之道，利而不害；圣人之道，为而不争。', '真实的话不华美，华美的话不真实。\n善良的人不巧辩，巧辩的人不善良。\n真正有知识的人不卖弄博学，卖弄博学的人不是真有知识。\n圣人不私自积藏，他尽量帮助别人，自己反而更充足；他尽量给予别人，自己反而更丰富。\n自然的规律是利物而不害物；圣人的准则是有所作为而不与人相争。', '本章为《道德经》全书结尾，总结了"为而不争"的核心思想。帮助他人、给予他人，自己反而更充实——这是老年人获得幸福感的智慧密码。');

-- =========================================================
-- 初始化种子数据：唐诗三百首 章节（精选8卷）
-- =========================================================
INSERT INTO classical_chapter (book_id, chapter_order, title, content, translation, annotation) VALUES
(4, 1, '卷一 · 五言古诗', '《感遇·其一》 张九龄\n兰叶春葳蕤，桂华秋皎洁。\n欣欣此生意，自尔为佳节。\n谁知林栖者，闻风坐相悦。\n草木有本心，何求美人折？\n\n《月下独酌》 李白\n花间一壶酒，独酌无相亲。\n举杯邀明月，对影成三人。\n月既不解饮，影徒随我身。\n暂伴月将影，行乐须及春。\n我歌月徘徊，我舞影零乱。\n醒时同交欢，醉后各分散。\n永结无情游，相期邈云汉。\n\n《春思》 李白\n燕草如碧丝，秦桑低绿枝。\n当君怀归日，是妾断肠时。\n春风不相识，何事入罗帏？', '张九龄《感遇》：春天的兰草繁茂葱茏，秋天的桂花皎洁明净。这欣欣向荣的生命力，自然成就了美好的季节。谁知山林中的隐者，闻到花香便心生喜悦。草木自有其本性，何必求美人来采摘呢？\n\n李白《月下独酌》：花丛中一壶美酒，独自饮酒没有亲近的人在旁。举起酒杯邀请明月，对着影子就变成了三个人。月既不懂得饮酒的乐趣，影子也只是徒然跟随我身。暂且与月和影作伴，行乐须趁这大好春光。我歌唱时月儿徘徊，我起舞时影子零乱。清醒时一起欢乐，醉后各自分散。愿永远结为忘情之游，相约在遥远的银河。\n\n李白《春思》：燕地的芳草如碧绿的丝线，秦地的桑树低垂着绿色的枝条。当你思念归家之日，正是我肝肠寸断之时。春风啊，你我素不相识，为何要吹入我的罗帐？', '本卷收录了张九龄、李白等人的五言古诗。李白《月下独酌》以奇幻的想象将孤独化为诗意，是唐诗中最具浪漫主义色彩的作品之一。'),
(4, 2, '卷二 · 五言乐府', '《游子吟》 孟郊\n慈母手中线，游子身上衣。\n临行密密缝，意恐迟迟归。\n谁言寸草心，报得三春晖。\n\n《长干行》 李白\n妾发初覆额，折花门前剧。\n郎骑竹马来，绕床弄青梅。\n同居长干里，两小无嫌猜。\n十四为君妇，羞颜未尝开。\n低头向暗壁，千唤不一回。\n十五始展眉，愿同尘与灰。\n常存抱柱信，岂上望夫台。', '孟郊《游子吟》：慈母手中的针线，游子身上的衣裳。临行前密密地缝着，心里担忧孩子迟迟不归。谁说小草一样微弱的孝心，能报答得了春天阳光般的慈母恩情？\n\n李白《长干行》：我刘海刚遮住额头时，在门前折花玩耍。郎君骑着竹马过来，绕着井栏追逐，拨弄着青梅。同在长干里居住，两小无猜。十四岁做了你的妻子，羞涩的面容从未展开。低头向着黑暗的墙壁，千呼万唤也不回头。十五岁才开始舒展眉头，情愿与你同化为尘与灰。', '《游子吟》是中国最著名的母爱诗篇，以线缝衣的细节传达深厚母爱。"寸草春晖"成为千古名喻。《长干行》"青梅竹马"、"两小无猜"等成语均源于此。'),
(4, 3, '卷三 · 七言古诗', '《登幽州台歌》 陈子昂\n前不见古人，后不见来者。\n念天地之悠悠，独怆然而涕下。\n\n《将进酒》 李白\n君不见，黄河之水天上来，奔流到海不复回。\n君不见，高堂明镜悲白发，朝如青丝暮成雪。\n人生得意须尽欢，莫使金樽空对月。\n天生我材必有用，千金散尽还复来。\n烹羊宰牛且为乐，会须一饮三百杯。', '陈子昂《登幽州台歌》：向前看不到古代的贤君，向后看不到未来的明主。想到天地悠悠无穷无尽，不禁独自悲伤，潸然泪下。\n\n李白《将进酒》：你难道没有看见吗？黄河之水仿佛从天而降，奔流到海不再回头。你难道没有看见吗？高堂上的明镜中悲叹白发，早晨还是青丝，傍晚就变成了雪白。人生得意之时就要尽情欢乐，不要让金杯空对明月。天生我材必定有用，千金散尽了还会再回来。烹羊宰牛暂且尽情欢乐，应当一饮三百杯。', '《将进酒》是李白最负盛名的作品，以豪放的笔触表达了人生苦短、及时行乐的思想。"天生我材必有用"成为千古励志名句。'),
(4, 4, '卷四 · 七言乐府', '《金缕衣》 佚名\n劝君莫惜金缕衣，劝君惜取少年时。\n花开堪折直须折，莫待无花空折枝。\n\n《清平调·其一》 李白\n云想衣裳花想容，春风拂槛露华浓。\n若非群玉山头见，会向瑶台月下逢。', '《金缕衣》：劝你不要珍惜那华贵的金缕衣，劝你要珍惜青春年少的时光。花开的时候可以折取就要去折取，不要等到花落了才去折取空枝。\n\n李白《清平调》：看见云彩就想到她的衣裳，看见花朵就想到她的容貌，春风吹拂栏杆，露水滋润花朵更显娇艳。如果不是在群玉山上见到她，那一定是在瑶台的月光下才能相逢。', '《金缕衣》是最著名的劝人珍惜时光的诗篇。"花开堪折直须折"成为珍惜当下的经典名句。'),
(4, 5, '卷五 · 五言律诗', '《春望》 杜甫\n国破山河在，城春草木深。\n感时花溅泪，恨别鸟惊心。\n烽火连三月，家书抵万金。\n白头搔更短，浑欲不胜簪。\n\n《山居秋暝》 王维\n空山新雨后，天气晚来秋。\n明月松间照，清泉石上流。\n竹喧归浣女，莲动下渔舟。\n随意春芳歇，王孙自可留。', '杜甫《春望》：国家破碎了山河依旧，春天来了城中草木茂盛。感伤时局，看到花开也流泪；怨恨离别，听到鸟鸣也心惊。战火连绵已三个月，一封家书值万两黄金。白发越搔越短，简直要插不住簪子了。\n\n王维《山居秋暝》：空旷的山中刚下过雨，天气已是晚来秋意。明月透过松林洒下清辉，清泉在石上淙淙流淌。竹林喧响是浣衣女归来，莲叶晃动是渔舟下水。任凭春天的芳菲消歇，王孙自然可以留居山中。', '杜甫《春望》写于安史之乱期间，"家书抵万金"道尽战乱中亲情的珍贵。王维《山居秋暝》以诗中有画的笔法描绘了山水田园的宁静之美。'),
(4, 6, '卷六 · 七言律诗', '《登高》 杜甫\n风急天高猿啸哀，渚清沙白鸟飞回。\n无边落木萧萧下，不尽长江滚滚来。\n万里悲秋常作客，百年多病独登台。\n艰难苦恨繁霜鬓，潦倒新停浊酒杯。\n\n《无题》 李商隐\n相见时难别亦难，东风无力百花残。\n春蚕到死丝方尽，蜡炬成灰泪始干。\n晓镜但愁云鬓改，夜吟应觉月光寒。\n蓬山此去无多路，青鸟殷勤为探看。', '杜甫《登高》：风急天高猿猴啼声悲哀，水清沙白鸟儿盘旋来回。无边无际的落叶萧萧而下，奔流不息的长江滚滚而来。万里悲秋长年漂泊在外，一生多病今日独自登台。历尽艰难苦恨，双鬓已白如霜，穷困潦倒，刚刚戒了酒不能再举杯。\n\n李商隐《无题》：相见不容易离别更不容易，东风无力百花凋残。春蚕到死才把丝吐尽，蜡烛燃尽蜡泪才流干。早晨照镜只愁云鬓改变，夜晚吟诗应觉月光清寒。蓬莱山离这里没有多远，殷勤的青鸟啊请替我探看。', '杜甫《登高》被誉为"古今七律第一"，气势磅礴，沉郁顿挫。李商隐《无题》"春蚕到死丝方尽"比喻至死不渝的深情。'),
(4, 7, '卷七 · 五言绝句', '《静夜思》 李白\n床前明月光，疑是地上霜。\n举头望明月，低头思故乡。\n\n《登鹳雀楼》 王之涣\n白日依山尽，黄河入海流。\n欲穷千里目，更上一层楼。\n\n《江雪》 柳宗元\n千山鸟飞绝，万径人踪灭。\n孤舟蓑笠翁，独钓寒江雪。', '李白《静夜思》：床前洒满明亮的月光，怀疑是地上结了霜。抬头望着天上的明月，低头思念远方的故乡。\n\n王之涣《登鹳雀楼》：太阳靠着西山落下，黄河向着大海奔流。想要看到千里之外的景色，就要再登上一层楼。\n\n柳宗元《江雪》：千座山间鸟儿飞尽，万条路上人迹无踪。孤舟上披蓑戴笠的老翁，独自在寒冷的江雪中垂钓。', '《静夜思》是中国人最熟悉的思乡诗。《登鹳雀楼》"更上一层楼"激励人不断进取。《江雪》以极简笔墨勾勒出独立寒江的孤傲形象。'),
(4, 8, '卷八 · 七言绝句', '《出塞》 王昌龄\n秦时明月汉时关，万里长征人未还。\n但使龙城飞将在，不教胡马度阴山。\n\n《凉州词》 王翰\n葡萄美酒夜光杯，欲饮琵琶马上催。\n醉卧沙场君莫笑，古来征战几人回？\n\n《枫桥夜泊》 张继\n月落乌啼霜满天，江枫渔火对愁眠。\n姑苏城外寒山寺，夜半钟声到客船。', '王昌龄《出塞》：依旧是秦汉时的明月和边关，万里长征的将士仍未归还。只要龙城的飞将军还在，绝不会让胡人的骑兵越过阴山。\n\n王翰《凉州词》：葡萄美酒倒满了夜光杯，正要开怀畅饮，琵琶声已在马上催促出发。醉卧沙场请你不要笑话，自古以来出征打仗有几人能回来？\n\n张继《枫桥夜泊》：月亮落下，乌鸦啼叫，寒霜满天，江边的枫树和渔火，陪伴着愁绪满怀无法入眠的旅人。姑苏城外的寒山寺，半夜的钟声传到了客船上。', '《枫桥夜泊》以"夜半钟声"的意象营造出深远的意境，使寒山寺成为千古名胜。《出塞》表达了保家卫国的壮志豪情。');

-- =========================================================
-- 初始化种子数据：菜根谭 章节（精选4卷）
-- =========================================================
INSERT INTO classical_chapter (book_id, chapter_order, title, content, translation, annotation) VALUES
(7, 1, '卷一 · 修身', '欲做精金美玉的人品，定从烈火中煅来；思立掀天揭地的事功，须向薄冰上履过。\n\n士人有百折不回之真心，才有万变不穷之妙用。\n\n立业建功，事事要从实地着脚，若少慕声闻，便成伪果；讲道修德，念念要从虚处立基，若稍计功效，便落尘情。\n\n醴肥辛甘非真味，真味只是淡；神奇卓异非至人，至人只是常。', '想要拥有精金美玉般的品德，一定要经过烈火的煅烧；想要建立惊天动地的事业，必须像在薄冰上行走一样小心谨慎。\n\n读书人要有百折不挠的真心，才能有应对万变的妙用。\n\n建功立业，每一件事都要脚踏实地去做，如果稍微贪慕虚名，就变成虚伪的成果；讲求道德修养，每一个念头都要从虚静处着手，如果稍微计较功效，就落入世俗之情。\n\n浓烈肥甘、辛辣甜美不是真正的美味，真正的美味只是清淡；神奇卓异不是真正的至人，真正的至人只是平常。', '修身卷教导人们：品德需经磨炼，事业需脚踏实地，真正的美味是清淡，真正的至人是平常心。对老年人来说，"真味只是淡，至人只是常"是最深刻的智慧。'),
(7, 2, '卷二 · 应酬', '使人有面前之誉，不若使其无背后之毁；使人有乍交之欢，不若使其无久处之厌。\n\n处世让一步为高，退步即进步的张本；待人宽一分是福，利人实利己的根基。\n\n攻人之恶毋太严，要思其堪受；教人以善毋过高，当使其可从。\n\n不责人小过，不发人阴私，不念人旧恶。三者可以养德，亦可以远害。', '与其让人当面称赞你，不如让人不在背后诋毁你；与其让人初交时觉得欢喜，不如让人长久相处而不厌烦。\n\n处世退让一步是高明的，退步恰是进步的准备；待人宽厚一分是有福的，利人实际是利己的根本。\n\n指责别人的过错不要太严厉，要考虑他能不能承受；教导别人行善不要标准太高，应当让他能够做到。\n\n不责备别人的小过失，不揭发别人的隐私，不计较别人过去的错误。这三者可以修养品德，也可以远离祸害。', '应酬卷教导处世之道：退一步海阔天空，宽一分是福气。"不责人小过，不发人阴私，不念人旧恶"是老年人保持内心平和的要诀。'),
(7, 3, '卷三 · 闲适', '昼闲人寂，听数声鸟语悠扬，不觉耳根尽彻；夜静天高，看一片云光舒卷，顿令眼界俱空。\n\n宠辱不惊，闲看庭前花开花落；去留无意，漫随天外云卷云舒。\n\n林间松韵，石上泉声，静里听来，识天地自然鸣佩；草际烟光，水心云影，闲中观去，见乾坤最上文章。\n\n岁月本长，而忙者自促；天地本宽，而卑者自隘；风花雪月本闲，而劳攘者自冗。', '白天闲暇人声寂静，听到几声悠扬的鸟鸣，不觉耳根清净无比；夜晚宁静天高气爽，看到一片云光舒展卷收，顿时让眼界开阔空明。\n\n受宠受辱都不惊惶，悠闲地看着庭前花朵开放凋落；去留都不在意，随意地看着天外云朵舒卷自如。\n\n林间的松涛声，石上的泉流声，在静中听来，能体认天地自然的鸣佩之音；草际的烟光，水中的云影，在闲中看去，能见到乾坤最妙的文章。\n\n岁月本来悠长，而忙碌的人自己把它缩短了；天地本来宽广，而卑微的人自己把它狭隘了；风花雪月本来悠闲，而劳碌的人自己把它复杂化了。', '闲适卷是《菜根谭》中最令人心旷神怡的篇章。"宠辱不惊，闲看庭前花开花落"是中国文化中最著名的豁达名言之一，极适合老年人颐养心性。'),
(7, 4, '卷四 · 概论', '文章做到极处，无有他奇，只是恰好；人品做到极处，无有他异，只是本然。\n\n绳锯木断，水滴石穿，学道者须要努力；水到渠成，瓜熟蒂落，得道者一任天机。\n\n风来疏竹，风过而竹不留声；雁度寒潭，雁去而潭不留影。故君子事来而心始现，事去而心随空。\n\n宠辱不惊，肝木自宁；动静以敬，心火自定；饮食有节，脾土不泄；调息寡言，肺金自全；恬淡无欲，肾水自足。', '文章做到极致，没有别的奇特之处，只是恰到好处；人品做到极致，没有别的特异之处，只是回归本然。\n\n绳子可以锯断木头，水滴可以穿透石头，学道的人必须努力；水到自然成渠，瓜熟自然蒂落，得道的人一切顺其自然。\n\n风吹过稀疏的竹林，风过后竹不留声响；大雁飞过寒冷的潭水，雁去后潭不留倒影。所以君子事情来了心才动，事情过了心就空。\n\n受宠受辱都不惊惶，肝脏自然安宁；动静都保持恭敬，心火自然安定；饮食有节制，脾胃不会泄败；调节呼吸少说话，肺金自然保全；恬淡无欲，肾水自然充足。', '概论卷融合了儒道佛三家思想，最终归结到"本然"二字。"风来疏竹"的比喻教导人们保持内心的空灵，不被外物所扰，是老年人修心的最高境界。');

